                  </div>
                ))}
              </div>
            </CardContent>
          </Card>
        )}

        {/* Product Management */}
        <Card>
          <CardHeader>
            <CardTitle className="text-foreground">Your Products</CardTitle>
          </CardHeader>
          <CardContent>
            {productsLoading ? (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
